import{_ as e,o as n,c as a,a2 as o}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"TongAgents — Benchmarks","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/tongagents/benchmarks.md","filePath":"research/agents/tongagents/benchmarks.md"}'),r={name:"research/agents/tongagents/benchmarks.md"};function s(i,t,l,d,h,g){return n(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="tongagents-—-benchmarks" tabindex="-1">TongAgents — Benchmarks <a class="header-anchor" href="#tongagents-—-benchmarks" aria-label="Permalink to &quot;TongAgents — Benchmarks&quot;">​</a></h1><blockquote><p>Terminal-Bench 2.0 results and comparison with other coding agents.</p></blockquote><h2 id="terminal-bench-2-0" tabindex="-1">Terminal-Bench 2.0 <a class="header-anchor" href="#terminal-bench-2-0" aria-label="Permalink to &quot;Terminal-Bench 2.0&quot;">​</a></h2><p><strong>Terminal-Bench 2.0</strong> is a benchmark evaluating coding agents in realistic CLI environments. Published at <strong>ICLR 2026</strong> and part of the <strong>Artificial Analysis Intelligence Index v4.0</strong>, it tests agents across 89 tasks spanning:</p><ul><li>Server configuration</li><li>Debugging</li><li>Security hardening</li><li>Data science workflows</li><li>Compilation and build systems</li></ul><p>Tasks are executed in Docker containers with realistic system environments. Agents must interact via shell commands to complete each task.</p><h2 id="tongagents-results" tabindex="-1">TongAgents Results <a class="header-anchor" href="#tongagents-results" aria-label="Permalink to &quot;TongAgents Results&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Configuration</th><th>Score</th><th>Confidence Interval</th><th>Rank</th><th>Date</th></tr></thead><tbody><tr><td>TongAgents + Gemini 3.1 Pro</td><td><strong>80.2%</strong></td><td>±2.6</td><td><strong>#3</strong></td><td>2026-03-13</td></tr><tr><td>TongAgents + Claude Opus 4.6</td><td><strong>~71.9%</strong></td><td>—</td><td><strong>#13</strong></td><td>2026-03</td></tr></tbody></table><h3 id="key-observations" tabindex="-1">Key Observations <a class="header-anchor" href="#key-observations" aria-label="Permalink to &quot;Key Observations&quot;">​</a></h3><ul><li><strong>80.2% is one of the highest scores</strong> on Terminal-Bench 2.0, placing TongAgents among the top 3 agents</li><li>The <strong>±2.6 confidence interval</strong> is typical for the benchmark (89 tasks → moderate statistical power)</li><li>The <strong>~8pp gap</strong> between Gemini 3.1 Pro and Claude Opus 4.6 is one of the larger model-dependent gaps on the leaderboard</li><li>Both results are from the same agent framework, demonstrating model-agnostic design</li></ul><h2 id="leaderboard-context-approximate-march-2026" tabindex="-1">Leaderboard Context (Approximate, March 2026) <a class="header-anchor" href="#leaderboard-context-approximate-march-2026" aria-label="Permalink to &quot;Leaderboard Context (Approximate, March 2026)&quot;">​</a></h2><p>To contextualize TongAgents&#39; performance, here is an approximate view of the Terminal-Bench 2.0 leaderboard around the time of submission:</p><table tabindex="0"><thead><tr><th>Rank</th><th>Agent</th><th>Score</th><th>Model</th></tr></thead><tbody><tr><td>#1</td><td>Top agent</td><td>~83-85%</td><td>—</td></tr><tr><td>#2</td><td>Second agent</td><td>~81-82%</td><td>—</td></tr><tr><td><strong>#3</strong></td><td><strong>TongAgents</strong></td><td><strong>80.2%</strong></td><td><strong>Gemini 3.1 Pro</strong></td></tr><tr><td>#4-12</td><td>Various agents</td><td>72-80%</td><td>Various</td></tr><tr><td><strong>#13</strong></td><td><strong>TongAgents</strong></td><td><strong>~71.9%</strong></td><td><strong>Claude Opus 4.6</strong></td></tr></tbody></table><p><em>Note: Exact leaderboard positions of other agents are approximate and may have shifted since TongAgents&#39; submission.</em></p><h2 id="performance-analysis" tabindex="-1">Performance Analysis <a class="header-anchor" href="#performance-analysis" aria-label="Permalink to &quot;Performance Analysis&quot;">​</a></h2><h3 id="strengths-inferred" tabindex="-1">Strengths (Inferred) <a class="header-anchor" href="#strengths-inferred" aria-label="Permalink to &quot;Strengths (Inferred)&quot;">​</a></h3><ul><li><strong>Consistent high performance</strong> — achieving 80%+ on a benchmark with diverse task types suggests robust generalization</li><li><strong>Multi-model viability</strong> — competitive scores with both Gemini and Claude</li><li><strong>Complex task handling</strong> — Terminal-Bench tasks require multi-step reasoning, suggesting strong planning capabilities</li></ul><h3 id="model-sensitivity" tabindex="-1">Model Sensitivity <a class="header-anchor" href="#model-sensitivity" aria-label="Permalink to &quot;Model Sensitivity&quot;">​</a></h3><p>The performance gap between models deserves analysis:</p><table tabindex="0"><thead><tr><th>Factor</th><th>Gemini 3.1 Pro Advantage</th></tr></thead><tbody><tr><td>Context window</td><td>1M+ tokens vs 200K</td></tr><tr><td>Tool calling</td><td>Potentially more reliable structured output</td></tr><tr><td>Reasoning depth</td><td>May handle complex multi-step plans better</td></tr></tbody></table><p>The gap could also reflect development bias — the agent may have been primarily tuned for Gemini.</p><h2 id="comparison-with-notable-agents" tabindex="-1">Comparison with Notable Agents <a class="header-anchor" href="#comparison-with-notable-agents" aria-label="Permalink to &quot;Comparison with Notable Agents&quot;">​</a></h2><p>Without exact scores for all competitors, we can note TongAgents&#39; relative position:</p><ul><li><strong>Top tier (&gt;80%)</strong> — TongAgents with Gemini 3.1 Pro belongs here, alongside only 2-3 other agents</li><li><strong>Upper tier (70-80%)</strong> — TongAgents with Claude Opus 4.6, competitive but not leading</li><li><strong>Mid tier (60-70%)</strong> — many well-known agents cluster here</li></ul><p>Reaching the top tier with <em>any</em> model configuration is a significant achievement, especially for an agent from an institution not previously known for coding agent work.</p><h2 id="other-benchmarks" tabindex="-1">Other Benchmarks <a class="header-anchor" href="#other-benchmarks" aria-label="Permalink to &quot;Other Benchmarks&quot;">​</a></h2><p>No results for TongAgents have been found on other coding agent benchmarks:</p><ul><li><strong>SWE-bench</strong> — no submission found</li><li><strong>HumanEval / MBPP</strong> — no submission found</li><li><strong>Aider polyglot</strong> — no submission found</li></ul><p>This may indicate that Terminal-Bench 2.0 was chosen as the initial public demonstration, with other benchmarks to follow.</p><h2 id="what-we-d-like-to-know" tabindex="-1">What We&#39;d Like to Know <a class="header-anchor" href="#what-we-d-like-to-know" aria-label="Permalink to &quot;What We&#39;d Like to Know&quot;">​</a></h2><ul><li>Per-category breakdowns (which task types does TongAgents excel at?)</li><li>Results with additional models (GPT-5, Qwen, Llama)</li><li>SWE-bench or other benchmark submissions for cross-benchmark comparison</li><li>Ablation studies showing which components contribute most to performance</li></ul>',31)])])}const p=e(r,[["render",s]]);export{m as __pageData,p as default};
